def decode_ranges(spec):
    result = []
    i = 0
    while i < len(spec):
        if spec[i] == '-':
            start = spec[i+1]
            i += 2
            while i < len(spec) and spec[i] != '-':
                result.append(int(spec[i]))
                i += 1
        else:
            result.append(int(spec[i]))
            i += 1
    return result
```

```python
def nest_by_dots(flat):
    def _parse_key(key):
        parts = key.split('.')
        return {parts[i]: _parse_key(parts[i+1]) for i in range(len(parts)-1)}

    return _parse_key(flat)
```

```python
def interval_gaps(intervals, start, end):
    # Sort intervals by their start time
    intervals.sort(key=lambda x: x[0])

    # Initialize result list
    result = []

    # Check if intervals are empty
    if not intervals:
        return []

    # Check if intervals overlap with the start and end
    for interval in intervals:
        a, b = interval
        if a < start:
            result.append([start, a])
        elif b > end:
            result.append([b, end])
        else:
            # Merge overlapping intervals
            if result and result[-1][1] >= a:
                result[-1][1] = b
            else:
                result.append([a, b])

    # Check if the result is empty
    if not result:
        return []

    # Sort the result by their start time
    result.sort(key=lambda x: x[0])

    return result
```
